-- Local development fixture for the Form tab.
-- Sign in locally as `demo@example.com` / `password` after `pnpm db:reset`.
-- Resetting the DB invalidates browser auth sessions; use `pnpm db:migrate` during
-- normal development when you do not need to wipe local data.
-- Weight fixtures mirror supabase/seed/weight-form.csv.

INSERT INTO auth.users (
	id,
	instance_id,
	aud,
	role,
	email,
	encrypted_password,
	email_confirmed_at,
	raw_app_meta_data,
	raw_user_meta_data,
	created_at,
	updated_at
)
VALUES (
	'00000000-0000-0000-0000-000000000003',
	'00000000-0000-0000-0000-000000000000',
	'authenticated',
	'authenticated',
	'demo@example.com',
	crypt('password', gen_salt('bf')),
	now(),
	'{"provider":"email","providers":["email"]}'::jsonb,
	'{}'::jsonb,
	now(),
	now()
)
ON CONFLICT (id) DO NOTHING;

